4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies from underpopulation — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("Rule 1 Underpopulation: two adjacent cells both die — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("Rule 3 Overpopulation: center cell with >3 neighbors dies — full 3x3 of live cells, center (1,1) dies", () => {
15	    const gen0: Cell[] = [
16	      [0, 0], [1, 0], [2, 0],
17	      [0, 1], [1, 1], [2, 1],
18	      [0, 2], [1, 2], [2, 2],
19	    ];
20	    const result = nextGeneration(gen0);
21	    expect(result).not.toContainEqual([1, 1]);
22	  });
23	  it("Rule 4 Reproduction: dead cell with exactly 3 neighbors becomes alive — L-shape → block", () => {
24	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
25	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
26	      new Set(["0,0", "1,0", "0,1", "1,1"]),
27	    );
28	  });
29	  it("Rule 2 Survival: every cell in a 2x2 block has 3 neighbors and survives — block stays as block", () => {
30	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
31	    const result = nextGeneration(block);
32	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
33	      new Set(["0,0", "1,0", "0,1", "1,1"]),
